"""Braintrust Scorer (auto-generated by build.py)"""

from typing import Any
import os
import re

import braintrust
from openai import OpenAI
from pydantic import BaseModel


# =============================================================================
# Configuration
# =============================================================================

MODEL = "gpt-5-mini"
PROJECT_NAME = "On Site Agent"

NAME = "$NAME"
SLUG = "$SLUG"
DESCRIPTION = "$DESCRIPTION"

PROMPT = """$PROMPT"""


class ScorerParams(BaseModel):
    input: Any
    output: Any
    expected: Any = None
    metadata: dict[str, Any] = {}


# =============================================================================
# Data Extraction
# =============================================================================


def _extract_response_from_output(root_output: Any) -> str:
    """Extract response string from various output formats."""
    if not root_output:
        return ""
    if isinstance(root_output, dict):
        return root_output.get("content", "")
    if isinstance(root_output, list):
        for item in root_output:
            if not isinstance(item, dict) or "content" not in item:
                continue
            content = item["content"]
            if isinstance(content, str):
                return content
            if isinstance(content, list):
                for c in content:
                    if isinstance(c, dict) and "text" in c:
                        return c["text"]
    return ""


async def extract_data(
    input: Any, output: Any, metadata: dict[str, Any] | None, **kwargs
) -> dict:
    """Extract query, response, page_url, summary from scorer inputs."""
    query = ""
    response = ""
    page_url = ""
    summary = ""
    error = None

    # Strategy 1: Direct input/output args
    if input and isinstance(input, dict):
        query = input.get("message", "")
        page_url = input.get("page_url", "")
        summary = input.get("summary", "")
    elif input and isinstance(input, str):
        query = input

    if output and isinstance(output, dict):
        content = output.get("content")
        if isinstance(content, dict):
            response = content.get("text", str(content))
        elif isinstance(content, str):
            response = content
        elif content is not None:
            response = str(content)
        else:
            response = str(output)
    elif output and isinstance(output, str):
        response = output

    # Strategy 2: Trace spans (for pushed scorers where input/output are None)
    if not query or not response:
        trace = kwargs.get("trace")
        if trace:
            try:
                spans = await trace.get_spans()
                if spans and len(spans) > 0:
                    root = spans[0]

                    span_metadata = getattr(root, "metadata", None)
                    if span_metadata and isinstance(span_metadata, dict):
                        if not page_url:
                            page_url = span_metadata.get("page_url", "")
                        if not summary:
                            summary = span_metadata.get("summary", "")

                    if not query:
                        root_input = getattr(root, "input", None)
                        if root_input and isinstance(root_input, dict):
                            query = root_input.get("message", "")
                            if not page_url:
                                page_url = root_input.get("page_url", "")
                            if not summary:
                                summary = root_input.get("summary", "")
                        elif root_input and isinstance(root_input, list):
                            for msg in root_input:
                                if isinstance(msg, dict) and msg.get("role") == "user":
                                    content = msg.get("content", "")
                                    if isinstance(content, str):
                                        query = (
                                            content.replace("User: ", "", 1)
                                            if content.startswith("User: ")
                                            else content
                                        )
                                        break

                    if not response:
                        root_output = getattr(root, "output", None)
                        response = _extract_response_from_output(root_output)
            except Exception as e:
                error = f"Trace error: {e}"

    if metadata and isinstance(metadata, dict):
        if metadata.get("summary_included") and not summary:
            summary = "(Summary was included in conversation context)"

    return {
        "query": query,
        "response": response,
        "page_url": page_url or "(none)",
        "summary": summary or "(none)",
        "error": error,
    }


# =============================================================================
# Handler
# =============================================================================


async def handler(
    input: Any,
    output: Any,
    expected: Any = None,
    metadata: dict[str, Any] = None,
    **kwargs,
):
    data = await extract_data(input, output, metadata, **kwargs)

    if data["error"]:
        return {"score": None, "name": NAME, "metadata": {"error": data["error"]}}

    client = OpenAI(api_key=os.environ.get("OPENAI_API_KEY"))

    try:
        llm_response = client.chat.completions.create(
            model=MODEL,
            messages=[
                {
                    "role": "system",
                    "content": PROMPT.format(
                        query=data["query"],
                        page_url=data["page_url"],
                        summary=data["summary"],
                        response=data["response"],
                    ),
                }
            ],
            temperature=0,
        )

        result = llm_response.choices[0].message.content.strip()
        match = re.search(r"^\(?([abc])\)?", result, re.IGNORECASE)
        choice = match.group(1).lower() if match else "unknown"

        if choice == "c":
            return {
                "score": None,
                "name": NAME,
                "metadata": {"choice": choice, "reasoning": result},
            }
        elif choice == "a":
            return {
                "score": 1.0,
                "name": NAME,
                "metadata": {"choice": choice, "reasoning": result},
            }
        elif choice == "b":
            return {
                "score": 0.0,
                "name": NAME,
                "metadata": {"choice": choice, "reasoning": result},
            }
        else:
            return {
                "score": None,
                "name": NAME,
                "metadata": {"choice": choice, "reasoning": result},
            }

    except Exception as e:
        return {"score": None, "name": NAME, "metadata": {"error": str(e)}}


# =============================================================================
# Registration
# =============================================================================

project = braintrust.projects.create(name=PROJECT_NAME)

project.scorers.create(
    name=NAME,
    slug=SLUG,
    description=DESCRIPTION,
    handler=handler,
    parameters=ScorerParams,
    if_exists="replace",
)
